INSERT INTO dispatch_queue (
    fire_log_id, job_id, target_address, payload, status, retry_count, next_retry_time, create_time, update_time
) VALUES (
    #{fireLogId}, #{jobId}, #{targetAddress}, #{payload}, #{status}, #{retryCount}, #{nextRetryTime}, NOW(), NOW()
)

mapper.select:
SELECT id, fire_log_id, job_id, target_address, payload, status, retry_count, next_retry_time, create_time, update_time
FROM dispatch_queue
WHERE status = 'PENDING'
  AND next_retry_time  <=  #{nowTime}
ORDER BY next_retry_time ASC, id ASC
LIMIT #{limit}

SELECT COUNT(*)
FROM dispatch_queue
WHERE status = #{status}

SELECT id, fire_log_id, job_id, target_address, payload, status, retry_count, next_retry_time, create_time,
update_time
FROM dispatch_queue


        AND status = #{request.status}


        AND fire_log_id = #{request.fireLogId}


        AND job_id = #{request.jobId}


ORDER BY update_time DESC, id DESC

    LIMIT #{request.size} OFFSET ${(request.current - 1) * request.size}

SELECT COUNT(*)
FROM dispatch_queue


        AND status = #{request.status}


        AND fire_log_id = #{request.fireLogId}


